private String interpolateBundleMessage(String message, ResourceBundle bundle, Locale locale, boolean recursive) {
  TokenCollector tokenCollector = new TokenCollector(message, InterpolationTermType.PARAMETER);
  TokenIterator tokenIterator = new TokenIterator(tokenCollector.getTokenList());
  while (tokenIterator.hasMoreInterpolationTerms()) {
    String term = tokenIterator.nextInterpolationTerm();
    String resolvedParameterValue = resolveParameter(term, bundle, locale, recursive); // reads from bundle - no EL sanitization
    tokenIterator.replaceCurrentInterpolationTerm(resolvedParameterValue); // substitutes raw value into message
  }
  return tokenIterator.getInterpolatedMessage(); // message now contains potentially EL-injectable content
}

